(async()=>{let allFlorists;try{allFlorists=await api.fetchFlorists();}catch(err){console.error('Failed to load florists:',err);return;}function stars(rating){return '★'.repeat(Math.floor(rating))+(rating % 1 >=0.5 ? '½':'')+'☆'.repeat(5-Math.ceil(rating));}function getLocations(list){const set=new Set();list.forEach(f=>{const parts=f.location.split(',');set.add(parts[parts.length-1].trim());});return [...set].sort();}function render(list){const grid=document.getElementById('floristGrid');const count=document.getElementById('floristCount');if(count)count.textContent=`Showing ${list.length}florist${list.length !==1 ? 's':''}`;if(!grid)return;if(!list.length){grid.innerHTML='<div class="dir-empty" style="text-align:center;padding:4rem 2rem;color:var(--text-light);grid-column:1/-1"><i class="bi bi-search" style="font-size:3rem;display:block;margin-bottom:1rem;"></i><h3>No florists found</h3><p>Try adjusting your search or filters.</p></div>';return;}grid.innerHTML=list.map(f=> ` <div class="dir-card"> <div class="dir-img-wrap"> <img loading="lazy" src="${escapeHtml(f.image)}" alt="${escapeHtml(f.name)}"> <div class="dir-rating-badge"><span class="stars">${stars(f.rating)}</span> ${f.rating}</div> </div> <div class="dir-body"> <h3>${escapeHtml(f.name)}</h3> <div class="dir-location"><i class="bi bi-geo-alt-fill"></i> ${escapeHtml(f.location)}</div> <span class="dir-specialty">${escapeHtml(f.specialty)}</span> <div class="dir-desc">${escapeHtml(f.description || '')}</div> <div class="dir-portfolio"> ${(f.portfolio || []).slice(0,3).map(p=> `<img loading="lazy" src="${escapeHtml(p)}" alt="Portfolio">`).join('')}${(f.portfolio || []).length > 3 ? `<span style="width:60px;height:60px;border-radius:6px;border:1px solid var(--border-color);display:flex;align-items:center;justify-content:center;font-size:0.75rem;color:var(--text-light);background:var(--bg-light);">+${f.portfolio.length-3}</span>`:''}</div> <div style="font-size:0.85rem;color:var(--text-light);margin-bottom:0.75rem;display:flex;gap:1rem;"> <span><i class="bi bi-chat-dots"></i> ${f.reviews}reviews</span> <span><i class="bi bi-box-seam"></i> ${f.products}products</span> </div> <div class="dir-footer"> <a href="florist-profile.html?id=${escapeHtml(f.id)}" class="btn btn-primary btn-sm" style="text-decoration:none;display:block;">View Profile</a> <button class="btn btn-outline btn-sm" onclick="window.location.href='mailto:${escapeHtml(f.email || '')}'"><i class="bi bi-envelope"></i> Contact</button> </div> </div> </div> `).join('');}function filterAndSort(){const q=(document.getElementById('floristSearch')?.value || '').toLowerCase().trim();const sort=document.getElementById('floristSort')?.value || 'rating';const activeLoc=document.querySelector('.loc-chip.active');const loc=activeLoc ? activeLoc.textContent.trim():'';let list=allFlorists.filter(f=>{const matchSearch=!q || f.name.toLowerCase().includes(q)|| f.location.toLowerCase().includes(q)|| f.specialty.toLowerCase().includes(q);const matchLoc=!loc || loc==='All Locations' || f.location.includes(loc);return matchSearch && matchLoc;});if(sort==='rating')list.sort((a,b)=> b.rating-a.rating);else if(sort==='reviews')list.sort((a,b)=> b.reviews-a.reviews);else if(sort==='name')list.sort((a,b)=> a.name.localeCompare(b.name));render(list);}const locFilter=document.getElementById('locFilter');if(locFilter){const locations=getLocations(allFlorists);locFilter.innerHTML='<button class="loc-chip active" data-loc="">All Locations</button>'+locations.map(l=> `<button class="loc-chip" data-loc="${l}">${l}</button>`).join('');locFilter.addEventListener('click',e=>{const chip=e.target.closest('.loc-chip');if(!chip)return;locFilter.querySelectorAll('.loc-chip').forEach(c=> c.classList.remove('active'));chip.classList.add('active');filterAndSort();});}document.getElementById('floristSearch')?.addEventListener('input',filterAndSort);document.getElementById('floristSearchBtn')?.addEventListener('click',filterAndSort);document.getElementById('floristSort')?.addEventListener('change',filterAndSort);render(allFlorists);})();